name: "🧠 OMNIBRAIN — All Systems One Workflow"

on:
  schedule:
    - cron: '0 7 * * *'   # 7am UTC — morning full cycle
    - cron: '0 19 * * *'  # 7pm UTC — evening full cycle
  workflow_dispatch:
    inputs:
      mode:
        description: 'full | brain_only | ops_only | health_check'
        required: false
        default: 'full'

jobs:
  omnibrain:
    name: "🧠 OMNIBRAIN"
    runs-on: ubuntu-latest
    timeout-minutes: 90
    permissions:
      contents: write
      actions: write

    steps:
      - uses: actions/checkout@v4
        with:
          fetch-depth: 0
          token: ${{ secrets.GITHUB_TOKEN }}

      - uses: actions/setup-python@v5
        with:
          python-version: '3.11'

      - name: Install dependencies
        run: pip install requests 2>/dev/null || true

      - name: Configure git + dirs
        run: |
          git config user.name 'OMNIBRAIN'
          git config user.email 'omnibrain@meeko-nerve-center'
          mkdir -p data content public knowledge/world

      - name: "Phase 0a — System Manifest"
        run: python mycelium/system_manifest.py
        continue-on-error: true

      - name: "Phase 0b — Human Directives"
        env:
          NOTION_TOKEN: ${{ secrets.NOTION_TOKEN }}
          HF_TOKEN: ${{ secrets.HF_TOKEN }}
        run: python mycelium/notion_directives_reader.py
        continue-on-error: true

      - name: "Phase 1a — Self-Healer v2"
